-- Assign 4 photos with GPS to Downtown Survey Flight (180001)
UPDATE media SET flightId = 180001 WHERE id IN (10002, 10004, 10005, 10003) AND projectId = 1;

-- Assign 4 photos (mixed GPS) to Park Mapping Mission (180002)
UPDATE media SET flightId = 180002 WHERE id IN (10006, 10007, 10008, 10009) AND projectId = 1;

-- Assign 3 photos (no GPS) to Infrastructure Inspection (180003)
UPDATE media SET flightId = 180003 WHERE id IN (10001, 10010, 10011) AND projectId = 1;

-- Update media counts for each flight
UPDATE flights SET mediaCount = 4 WHERE id = 180001;
UPDATE flights SET mediaCount = 4 WHERE id = 180002;
UPDATE flights SET mediaCount = 3 WHERE id = 180003;

-- Verify the distribution
SELECT f.id, f.name, f.mediaCount, COUNT(m.id) as actual_count
FROM flights f
LEFT JOIN media m ON f.id = m.flightId
WHERE f.projectId = 1
GROUP BY f.id, f.name, f.mediaCount
ORDER BY f.id;

